#include <cstddef>
#include <cstdint>
#include <omp.h>

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Convert to a flat array for better cache locality
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

    const int stride = n;

#pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        const int k_offset = k * stride;
        // pre-load path[k][j] into a small buffer to avoid repeated accesses
        std::vector<int> row_k(n);
        std::copy(flat.begin() + k_offset, flat.begin() + k_offset + n, row_k.data());

        for (int i = 0; i < n; ++i) {
            int i_offset = i * stride;
            int aik = flat[i_offset + k];
            for (int j = 0; j < n; ++j) {
                int cand = aik + row_k[j];
                int& target = flat[i_offset + j];
                if (cand < target) target = cand;
            }
        }
    }

    // Copy back to the original 2D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n, path[i].begin());
}
