/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Each iteration of the outer loop works on a distinct row i.
    // Reading data from rows < i is safe because they are already
    // finished before the corresponding i-iteration starts.
    #pragma omp parallel for schedule(static) shared(A)
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();          // pointer to row i

        /* Off‑diagonal entries A[i][j] , j < i */
        for (int j = 0; j < i; ++j) {
            double* Aj = A[j].data();      // pointer to row j
            double sum = -Ai[j];
            for (int k = 0; k < j; ++k) {
                sum -= Ai[k] * Aj[k];
            }
            Ai[j] = sum / Aj[j];
        }

        /* Diagonal entry A[i][i] */
        double sq_sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sq_sum += Ai[k] * Ai[k];
        }
        Ai[i] = std::sqrt(Ai[i] - sq_sum);
    }
}
