void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // => Form  B := alpha*A**T*B.
    // A is MxM
    // B is MxN

    // Use OpenMP to parallelise the outer loop over rows of B.
    // Work is split over `m` threads by default, which matches the
    // target 8‑thread machine.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // Prefer row‑major access due to std::vector< std::vector<double> >
        // layout: each B[i] is a contiguous row.
        double* B_row = B[i].data();
        const double* A_col_i = nullptr;   // pointer to column i of A

        // We calculate the contribution of rows k = i+1 .. m-1 of A
        // to B[i][*].  For each column j we need A[k][i] which is the
        // i‑th column of A, accessed by stepping through each row k.
        for (int j = 0; j < n; ++j) {
            double sum = B_row[j];           // current value of B[i][j]
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B_row[j] = alpha * sum;
        }
    }
}
