/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Pre‑compute alpha once; the double loops below use the same value.
    const double alphaB = alpha;

    // Parallel over rows of C (and A, B). Each thread works on a distinct i.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Reduce C[i][j] by beta, only for j ≤ i (lower triangle).
        double* c_row = C[i].data();
        for (int j = 0; j <= i; ++j)
            c_row[j] *= beta;

        // Compute the outer products.
        for (int k = 0; k < m; ++k) {
            const double aik = alphaB * A[i][k];
            const double bik = alphaB * B[i][k];
            const double* a_col = &A[0][k]; // pointer to column k of A (row-major layout)
            const double* b_col = &B[0][k]; // pointer to column k of B
            for (int j = 0; j <= i; ++j) {
                c_row[j] += a_col[j] * bik + b_col[j] * aik;
            }
        }
    }
