#include <vector>

/*
 *  The kernel performs a forward substitution on a lower‑triangular matrix
 *  L.  Although the matrix is stored as a vector of vectors, the
 *  implementation uses raw pointers to the row data for maximum
 *  cache‑locality and to avoid virtual function overhead.
 *
 *  The algorithm loops over rows, computing the dot product of the
 *  current row of L (excluding the diagonal element) with the already
 *  computed entries of x, subtracting that from the corresponding
 *  source value and normalising by the diagonal entry.
 */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Treat each row as a contiguous array for faster access.
    // Bounds are guaranteed by the problem statement so we skip checks.
    for (int i = 0; i < n; ++i)
    {
        const double* Li  = L[i].data();  // pointer to ith row
        const double* Li0 = Li;           // start of the row
        double Xi = b[i];                 // initialise with RHS

        // Inner loop: compute dot product of L[i][j] * x[j] for j < i
        for (int j = 0; j < i; ++j)
            Xi -= Li[j] * x[j];

        // Normalise by the diagonal element L[i][i]
        x[i] = Xi / Li0[i];
    }
}
