/* Optimised 1‑D Jacobi kernel (gcc 13+, -O2 -fopenmp) */
#include <vector>
#include <omp.h>

constexpr double COEFF = 0.33333;

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Pointer access for speed
    double *a = A.data();
    double *b = B.data();

    // Temporary buffer to store the first and last element values
    double a0, an_1, b0, bn_1;

    for (int t = 0; t < tsteps; ++t) {
        // Preserve boundary values
        a0  = a[0];
        an_1 = a[n-1];
        b0  = b[0];
        bn_1 = b[n-1];

        /* Stage 1: A → B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = COEFF * (a[i-1] + a[i] + a[i+1]);
        }

        /* Restore boundary of B (unchanged from previous timestep) */
        b[0]      = b0;
        b[n-1]    = bn_1;

        /* Stage 2: B → A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = COEFF * (b[i-1] + b[i] + b[i+1]);
        }

        /* Restore boundary of A */
        a[0]      = a0;
        a[n-1]    = an_1;
    }
}
```
This version keeps identical boundary behaviour, uses raw pointers for cache‑friendly access, and parallelises both kernel stages with static scheduling to minimise scheduling overhead. The constant `COEFF` avoids repeated multiplication, and the small temporary buffers guarantee that boundary values are preserved exactly as the original implementation.

