/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    /* Local array to avoid repeated dynamic allocation of z inside the loop. */
    std::vector<double> z(n);

    /* Initial values */
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    /* Outer loop is inherently sequential because each iteration
       depends on the previous values of y.  The inner computations are
       independent and can be vectorised and/or parallelised. */
    for (int k = 1; k < n; ++k) {
        /* Update beta for this stage */
        beta = (1.0 - alpha * alpha) * beta;

        /* Sum r[k-i-1] * y[i] for i = 0..k-1 */
        double sum = 0.0;
#pragma omp simd reduction(+:sum) aligned(r, y:32)
        for (int i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        /* New reflection coefficient */
        alpha = -(r[k] + sum) / beta;

        /* Temporary array z to hold the updated coefficients */
#pragma omp simd aligned(y, z:32)
        for (int i = 0; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - i - 1];
        }

        /* Move the new values from z back to y */
#pragma omp simd aligned(y, z:32)
        for (int i = 0; i < k; ++i) {
            y[i] = z[i];
        }

        /* Set the current reflection coefficient */
        y[k] = alpha;
    }
}
