/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A) {
    const double inv9 = 1.0 / 9.0;       // constant denominator

    /* Acquire raw row pointers once – saves repeated lookups */
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i) row[i] = A[i].data();

    /* The outer time step loop is serial because each step depends on the results of the previous step. */
    for (int t = 0; t < tsteps; ++t) {
        /* Parallelise the row loop; boundary rows are omitted. */
        #pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i <= n - 2; ++i) {
            double *cur  = row[i];
            double *up   = row[i - 1];
            double *down = row[i + 1];

            /* Compute the new value for every interior column. */
            for (int j = 1; j <= n - 2; ++j) {
                cur[j] = (up[j - 1] + up[j] + up[j + 1] +
                          cur[j - 1]      + cur[j]      + cur[j + 1] +
                          down[j - 1] + down[j] + down[j + 1]) * inv9;
            }
        }
    }
}
