void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean) {
    /* 1.  compute column means   */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    /* 2.  subtract means (center the data) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* 3.  compute covariance (upper‑triangular and mirror) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double value = sum / (n - 1.0);
            cov[i][j] = value;
            cov[j][i] = value;   /* symmetry */
        }
    }
}
