/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<double>>& C4,
		    std::vector<double>& sum) {

    // Work locally with raw pointers for speed and predictability.
    const std::size_t Np = static_cast<std::size_t>(np);
    const std::size_t Nq = static_cast<std::size_t>(nq);
    const std::size_t Nr = static_cast<std::size_t>(nr);

    // Flattened data pointers
    for (std::size_t r = 0; r < Nr; ++r) {
        // Parallelise the outer two loops (over r and q) using OpenMP.
        // The compiler is free to schedule them as needed.
        #pragma omp parallel for collapse(2) schedule(static)
        for (std::size_t q = 0; q < Nq; ++q) {
            // Perform the inner matrix-vector multiplcations.
            const std::vector<double>& As = A[r][q];
            const double* Aptr = As.data();        // A[r][q][s]

            for (std::size_t p = 0; p < Np; ++p) {
                double accum = 0.0;
                const double* Cptr = C4[p].data(); // C4[s][p]
                const double* AptrS = Aptr;

                // SIMD-friendly inner loop
                #pragma omp simd reduction(+:accum)
                for (std::size_t s = 0; s < Np; ++s) {
                    accum += *AptrS++ * Cptr[s];
                }
                sum[p] = accum;
            }

            // Copy the result back into A
            double* Adest = A[r][q].data();
            for (std::size_t p = 0; p < Np; ++p) {
                Adest[p] = sum[p];
            }
        }
    }
}
