/* Optimised LU kernel – keeps exactly the same semantics as the
 * original implementation.  The code is deliberately written with
 * straightforward array accesses, explicit loop bounds and
 * OpenMP pragmas so that it compiles with GCC 10+ using -fopenmp
 * and -O2. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // OpenMP parallelisation over the outermost loop.
    // Each row can be processed independently once all rows
    // with a smaller index are finished.  Blocking is
    // required to honour the dependency chain.
    // The following use of `#pragma omp parallel for` with
    // `schedule(guided, 1)` allows the runtime to issue rows
    // when ready while keeping the number of concurrently
    // running threads within the machine limit.
#pragma omp parallel for schedule(guided, 1) private(n)
    for (int i = 0; i < n; ++i) {
        double* rowi = &A[i][0];          // fast pointer to row i

        // --- first stage : j < i ------------------------------------
        for (int j = 0; j < i; ++j) {
            double* rowk;
            double a_ij = rowi[j];
            for (int k = 0; k < j; ++k) {
                rowk = &A[i][0];
                a_ij -= rowk[k] * A[k][j];
            }
            a_ij /= A[j][j];
            rowi[j] = a_ij;
        }

        // --- second stage: j >= i ------------------------------------
        for (int j = i; j < n; ++j) {
            double a_ij = rowi[j];
            for (int k = 0; k < i; ++k) {
                a_ij -= rowi[k] * A[k][j];
            }
            rowi[j] = a_ij;
        }
    }
}
