#include <vector>
#include <cmath>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* 1. Mean */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    /* 2. Standard deviation (with eps guard) */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            s += d * d;
        }
        s /= static_cast<double>(n);
        s = std::sqrt(s);
        stddev[j] = (s <= eps) ? 1.0 : s;
    }

    /* 3. Normalise data */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* 4. Correlation matrix */
    /* Since corr[i][i] = 1.0 we set it once */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) corr[i][i] = 1.0;

    /* compute upper triangle and mirror */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;   // symmetry
        }
    }
}
