    /* For each time step we have two independent stencil updates:
          1) A -> B
          2) B -> A
       The updates are independent per element, so we parallelise over the
       2‑D tile (excluding halo rows/cols).  We keep the two passes
       sequential to preserve the exact data dependencies of the original
       algorithm. */
    for (int t = 0; t < tsteps; ++t) {
        /* First update: copy from A to B */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                B[i][j] = coeff * (A[i][j] + A[i][j-1] + A[i][j+1] +
