        for (int j = 0; j < n; ++j) c_flat[i * n + j] = C[i][j];
        for (int k = 0; k < m; ++k) a_flat[i * m + k] = A[i][k];
    }

    /* Parallelise the outermost loop.  Each iteration only writes to
       distinct rows of C, so the iterations are independent.  The
       `schedule(dynamic, 1)` helps balance load when `n` is large
       relative to the number of threads. */
    #pragma omp parallel for schedule(dynamic, 1) 
    for (int i = 0; i < n; ++i) {
        double* c_row = c_flat + i * n;
        const double* a_row = a_flat + i * m;

        // Scale lower triangle by beta
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= beta;
        }

        // Accumulate alpha * A[i][k] * A[j][k]
        for (int k = 0; k < m; ++k) {
            double aik = a_row[k];
            const double* a_col = a_flat + k; // stride = m
            // manually unroll 4-way for potential SIMD
            #pragma ivdep
