/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Create local pointers for fast access – this avoids repeated
    // indirection through operator[] of std::vector.
    std::vector<double*> Ap(n), Rp(n), Qp(n);
    for (int j = 0; j < n; ++j) {
        Ap[j]  = A[j].data();   // Note: A is stored column‑major in the harness
        Rp[j]  = R[j].data();
        Qp[j]  = Q[j].data();
    }

    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;
        double* Ak = Ap[k];
        double* Qk = Qp[k];

        // Compute the norm of the k‑th column
#pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i) {
            double v = Ak[i];
            nrm += v * v;
        }

        double Rkk = std::sqrt(nrm);
        Rp[k][k] = Rkk;

        // Normalize column into Q
#pragma omp simd
        for (int i = 0; i < m; ++i) {
            Qk[i] = Ak[i] / Rkk;
        }

        // Orthogonalize following columns
        for (int j = k + 1; j < n; ++j) {
            double* Aj = Ap[j];
            double* Rkj = Rp[k];
            double* Qkj = Qk;                // Q[:,k]
            double rkj = 0.0;

            // Compute R(k,j) = Q(:,k)^T * A(:,j)
#pragma omp simd reduction(+:rkj)
            for (int i = 0; i < m; ++i) {
                rkj += Qkj[i] * Aj[i];
            }
            Rkj[j] = rkj;

            // Update A(:,j) = A(:,j) - Q(:,k) * R(k,j)
#pragma omp simd
            for (int i = 0; i < m; ++i) {
                Aj[i] -= Qkj[i] * rkj;
            }
        }
    }
}
