// representation and OpenMP for parallelism. The code is careful to
// preserve the exact behavior of the original nested-vector version.

#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // obtain raw data pointers for constant‑time indexing
    // The matrices are stored row‑major in std::vector<std::vector<double>>
    // and we access them through flattened pointers.
    std::vector<double> flatA(ni * nk);
    std::vector<double> flatB(nk * nj);
    std::vector<double> flatC(ni * nj);

    for (int i = 0; i < ni; ++i)
        for (int k = 0; k < nk; ++k)
            flatA[i * nk + k] = A[i][k];

    for (int k = 0; k < nk; ++k)
        for (int j = 0; j < nj; ++j)
            flatB[k * nj + j] = B[k][j];

    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            flatC[i * nj + j] = C[i][j];

    // Block sizes chosen empirically for L1/L2 cache on typical x86‑64
    constexpr int Bk = 32;  // block size in k dimension
    constexpr int Bj = 64;  // block size in j dimension

    // Parallel over outer i‑loop.  Static scheduling keeps all
    // iterations balanced when the work is evenly sized.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* c_row = &flatC[i * nj];
        const double* a_row = &flatA[i * nk];

        // First multiply the existing C by beta
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        // Iterate over blocks in k and j
        for (int kk = 0; kk < nk; kk += Bk) {
            int k_end = std::min(kk + Bk, nk);
            for (int jj = 0; jj < nj; jj += Bj) {
                int j_end = std::min(jj + Bj, nj);
                for (int k = kk; k < k_end; ++k) {
                    double aik = alpha * a_row[k];
                    const double* b_row = &flatB[k * nj];
                    for (int j = jj; j < j_end; ++j)
                        c_row[j] += aik * b_row[j];
                }
            }
        }
    }

    // Copy the result back into the original std::vector<std::vector<double>>
    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            C[i][j] = flatC[i * nj + j];
