    /* ---------- Forward substitution: solve L*y = b (L is unit lower) -------- */
    for (int i = 0; i < n; ++i) {
        double w = b_ptr[i];
#pragma omp simd reduction(-:w)
        for (int j = 0; j < i; ++j) {
            w -= A_ref[i][j] * y_ptr[j];
        }
        y_ptr[i] = w;
    }

    /* ---------- Backward substitution: solve U*x = y (U is upper) ----------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y_ptr[i];
#pragma omp simd reduction(-:w)
        for (int j = i + 1; j < n; ++j) {
            w -= A_ref[i][j] * x_ptr[j];
        }
