/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

inline int match(int b1, int b2) noexcept {
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    /* The algorithm processes the DP table along increasing diagonal length.
       Dependencies are satisfied once a whole diagonal is complete, so we
       parallelise over the outer diagonal loop. */
    #pragma omp parallel for schedule(static)
    for (int d = 1; d < n; ++d) {          // diagonal length (j-i)
        for (int i = 0; i < n - d; ++i) {   // start index of substring
            int j = i + d;

            int best = table[i][j];

            /* Skip to the left cell */
            int val = table[i][j-1];
            if (val > best) best = val;

            /* Skip to the upper cell */
            val = table[i+1][j];
            if (val > best) best = val;

            /* Pair current boundaries if possible */
            val = table[i+1][j-1];
            if (i + 1 < j) {                 // ensures i+1 <= j-1
                if (i < j-1)
                    val += match(seq[i], seq[j]);
            }
            if (val > best) best = val;

            /* Split the interval into two subintervals */
            for (int k = i + 1; k < j; ++k) {
                int tmp = table[i][k] + table[k+1][j];
                if (tmp > best) best = tmp;
            }

            table[i][j] = best;
        }
    }
}
