/* Optimised kernel, preserves exact numerical behaviour of the original */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Flatten 2‑D vectors for cache friendliness */
    const int sz = n * n;
    std::vector<double> uf(sz), vf(sz), pf(sz), qf(sz);
    auto idx = [n](int i, int j) { return i * n + j; };

    /* Copy input to flat arrays (avoid aliasing during parallel loops) */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            uf[idx(i,j)] = u[i][j], vf[idx(i,j)] = v[i][j],
            pf[idx(i,j)] = p[i][j], qf[idx(i,j)] = q[i][j];

    for (int t = 1; t <= tsteps; ++t) {
        /* First sweep: treat columns */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            /* initialise boundary values */
            vf[idx(0,i)]   = 1.0;
            p[idx(i,0)]    = 0.0;
            qf[idx(i,0)]   = vf[idx(0,i)];

            /* forward sweep in j */
            for (int j = 1; j < n-1; ++j) {
                double denom = a * p[idx(i,j-1)] + b;
                p[idx(i,j)] = -c / denom;
                qf[idx(i,j)] = (-d * uf[idx(j,i-1)] + (1.0+2.0*d) * uf[idx(j,i)] -
                                f * uf[idx(j,i+1)] - a * qf[idx(i,j-1)]) / denom;
            }

            vf[idx(n-1,i)] = 1.0;

            /* backward sweep in j */
            for (int j = n-2; j >= 1; --j)
                vf[idx(j,i)] = p[idx(i,j)] * vf[idx(j+1,i)] + qf[idx(i,j)];
        }

        /* Second sweep: treat rows */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            uf[idx(i,0)]   = 1.0;
            p[idx(i,0)]    = 0.0;
            qf[idx(i,0)]   = uf[idx(i,0)];

            for (int j = 1; j < n-1; ++j) {
                double denom = d * p[idx(i,j-1)] + e;
                p[idx(i,j)]  = -f / denom;
                qf[idx(i,j)] = (-a * vf[idx(i-1,j)] + (1.0+2.0*a) * vf[idx(i,j)] -
                                c * vf[idx(i+1,j)] - d * qf[idx(i,j-1)]) / denom;
            }

            uf[idx(i,n-1)] = 1.0;
            for (int j = n-2; j >= 1; --j)
                uf[idx(i,j)] = p[idx(i,j)] * uf[idx(i,j+1)] + qf[idx(i,j)];
        }
    }

    /* Copy results back to the 2‑D containers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            u[i][j] = uf[idx(i,j)];
            v[i][j] = vf[idx(i,j)];
            p[i][j] = pf[idx(i,j)];
            q[i][j] = qf[idx(i,j)];
