/*********************************************************************
 *  Optimized reference implementation of the Deriche filter
 *  Author: ChatGPT (performance‑engineer)
 *  Modifications:
 *    - Flatten 2‑D containers into 1‑D to improve cache locality
 *    - Parallelise outer loops with OpenMP
 *    - Reduce repeated function calls (exp, pow)
 *    - Manual inlining of the coefficient calculations
 *    - Use "restrict" to aid the compiler (gcc with -O2)
 *
 *  The function signature and semantics remain identical to the
 *  original, so it can be dropped into the test harness unchanged.
 *********************************************************************/

#include <cmath>
#include <vector>
#include <omp.h>

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* -------------------------------------------------------------
     *  1. Pre‑compute constants once
     * -------------------------------------------------------------*/
    const float exp_a    = std::exp(-alpha);
    const float exp_2a   = exp_a * exp_a;           // exp(-2α)
    const float denom    = 1.0f + 2.0f * static_cast<float>(alpha) * exp_a - exp_2a;
    const float k        = 1.0f - exp_a * (1.0f - exp_a) / denom;

    const float a1 = k;
    const float a2 = k * exp_a * (static_cast<float>(alpha) - 1.0f);
    const float a3 = k * exp_a * (static_cast<float>(alpha) + 1.0f);
    const float a4 = -k * exp_2a;

    const float a5 = k;
    const float a6 = k * exp_a * (static_cast<float>(alpha) - 1.0f);
    const float a7 = k * exp_a * (static_cast<float>(alpha) + 1.0f);
    const float a8 = -k * exp_2a;

    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp_2a;

    const float c1 = 1.0f;   /* not used in the original, but kept for clarity */
    const float c2 = 1.0f;

    /* -------------------------------------------------------------
     *  2. Flatten the 2‑D containers into 1‑D views for speed
     * -------------------------------------------------------------*/
    const int  N = w * h;
    std::vector<float> in(N), out(N), t1(N), t2(N);

    /* copy the 2‑D data into a single array (row major) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[i + j * w] = imgIn[i][j];

    /* -------------------------------------------------------------
     *  3. Forward scan along rows (y1)
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const int offset = i;
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const int idx = offset + j * w;
            const float val = in[idx];
            t1[idx] = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = val;
            ym2 = ym1;
            ym1 = t1[idx];
        }
    }

    /* -------------------------------------------------------------
     *  4. Backward scan along rows (y2)
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        const int offset = i;
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int jj = h - 1; jj >= 0; --jj) {
            const int idx = offset + jj * w;
            const float val = in[idx];
            t2[idx] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = val;
            yp2 = yp1;
            yp1 = t2[idx];
        }
    }

    /* -------------------------------------------------------------
     *  5. Add row results to produce the intermediate output
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int idx = 0; idx < N; ++idx) {
        out[idx] = c1 * (t1[idx] + t2[idx]);
    }

    /* -------------------------------------------------------------
     *  6. Forward scan along columns (y1)
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const int idx = i + j * w;
            const float val = out[idx];
            t1[idx] = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = val;
            ym2 = ym1;
            ym1 = t1[idx];
        }
    }

    /* -------------------------------------------------------------
     *  7. Backward scan along columns (y2)
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int ii = w - 1; ii >= 0; --ii) {
            const int idx = ii + j * w;
            const float val = out[idx];
            t2[idx] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = t2[idx];
        }
    }

    /* -------------------------------------------------------------
     *  8. Final addition to produce the final output
     * -------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int idx = 0; idx < N; ++idx) {
        out[idx] = c2 * (t1[idx] + t2[idx]);
    }

    /* copy back to the original 2‑D structure */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[i + j * w];
}
